#include <bits/stdc++.h>
using namespace std;
int n,a[20],b[20],anss[20],ans=1e9;
bool vis[20];
void dfs(int x,int sum)
{
	if(x>n)
    {
		ans=min(ans,sum);
		return ;
	}
	if(sum>=ans) return ;
	for(int i=1;i<=n;i++)
    {
		if(vis[i]) continue;
		vis[i]=1;
		anss[x]=i;
		if(x==1) dfs(x+1,1);
		else dfs(x+1,sum+max(b[anss[x-1]],a[i])+1);
		anss[x]=0;
		vis[i]=0;
	}
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++) cin>>b[i];
	dfs(1,1);
	cout<<ans<<"\n";
    return 0;
}
